#include <stdio.h>
#include <string.h>
#define MAXN 100005
#define MAXM 1005
#define VOWELS 5

int main() {
    int T, N;
    char dish[MAXN][MAXM];
    int vowelMask[MAXN];
    int i, j, k, count;

    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%s", dish[i]);
            vowelMask[i] = 0;
            for (j = 0; j < strlen(dish[i]); j++) {
                switch (dish[i][j]) {
                    case 'a': vowelMask[i] |= 1; break;
                    case 'e': vowelMask[i] |= 2; break;
                    case 'i': vowelMask[i] |= 4; break;
                    case 'o': vowelMask[i] |= 8; break;
                    case 'u': vowelMask[i] |= 16; break;
                }
            }
        }

        count = 0;
        for (i = 0; i < N; i++) {
            for (j = i + 1; j < N; j++) {
                if ((vowelMask[i] | vowelMask[j]) == 31) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

