import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String[] dish = new String[N];
            int[] vowelMask = new int[N];
            for (int i = 0; i < N; i++) {
                dish[i] = sc.next();
                vowelMask[i] = 0;
                for (char c : dish[i].toCharArray()) {
                    switch (c) {
                        case 'a': vowelMask[i] |= 1; break;
                        case 'e': vowelMask[i] |= 2; break;
                        case 'i': vowelMask[i] |= 4; break;
                        case 'o': vowelMask[i] |= 8; break;
                        case 'u': vowelMask[i] |= 16; break;
                    }
                }
            }

            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if ((vowelMask[i] | vowelMask[j]) == 31) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

